const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { Client } = require('pg'); // Assuming PostgreSQL for database

const sqsClient = new SQSClient({ region: 'your-region' });
const queueUrl = 'your-sqs-queue-url';

const dbClient = new Client({
  user: 'your-db-user',
  host: 'your-db-host',
  database: 'your-db-name',
  password: 'your-db-password',
  port: 5432,
});

async function processMessage(message) {
  const transaction = JSON.parse(message.Body);
  
  // Example database update based on transaction
  const query = 'UPDATE accounts SET balance = balance + $1 WHERE account_id = $2';
  const values = [transaction.amount, transaction.accountId];

  await dbClient.query(query, values);
}

async function consumeMessages() {
  await dbClient.connect();

  try {
    const command = new ReceiveMessageCommand({
      QueueUrl: queueUrl,
      MaxNumberOfMessages: 10,
      WaitTimeSeconds: 20,
    });

    const data = await sqsClient.send(command);

    if (data.Messages) {
      for (const message of data.Messages) {
        try {
          await processMessage(message);

          const deleteCommand = new DeleteMessageCommand({
            QueueUrl: queueUrl,
            ReceiptHandle: message.ReceiptHandle,
          });

          await sqsClient.send(deleteCommand);
        } catch (error) {
          console.error('Error processing message:', error);
        }
      }
    }
  } catch (error) {
    console.error('Error receiving messages:', error);
  } finally {
    await dbClient.end();
  }
}

setInterval(consumeMessages, 5000); // Poll every 5 seconds